package com.example.oauthclient;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;

import jakarta.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;
import java.util.LinkedHashMap;
import java.util.Map;
import java.util.stream.Collectors;

@SpringBootApplication
public class OAuthClientApplication {
    public static void main(String[] args) {
        SpringApplication.run(OAuthClientApplication.class, args);
    }
}

@Controller
class OAuthRedirectController {

    private static final String AUTHORIZATION_ENDPOINT = "https://authorization-server.example.com/oauth2/authorize";
    private static final String CLIENT_ID = "your-client-id";
    private static final String REDIRECT_URI = "http://localhost:8080/oauth/callback";
    private static final String SCOPE = "openid profile email";
    private static final String RESPONSE_TYPE = "code";

    @GetMapping("/oauth/login")
    public void login(HttpServletResponse response) throws IOException {
        String authorizationUrl = buildAuthorizationUrl(
                AUTHORIZATION_ENDPOINT,
                CLIENT_ID,
                REDIRECT_URI,
                SCOPE,
                RESPONSE_TYPE
        );

        response.setStatus(HttpStatus.FOUND.value());
        response.setHeader(HttpHeaders.LOCATION, authorizationUrl);
    }

    private String buildAuthorizationUrl(String authorizationEndpoint,
                                         String clientId,
                                         String redirectUri,
                                         String scope,
                                         String responseType) {
        Map<String, String> params = new LinkedHashMap<>();
        params.put("client_id", clientId);
        params.put("redirect_uri", redirectUri);
        params.put("scope", scope);
        params.put("response_type", responseType);

        String query = params.entrySet().stream()
                .map(e -> encode(e.getKey()) + "=" + encode(e.getValue()))
                .collect(Collectors.joining("&"));

        return authorizationEndpoint + "?" + query;
    }

    private String encode(String value) {
        return URLEncoder.encode(value, StandardCharsets.UTF_8);
    }
}